import keyboard
import time

def log_keypresses():
    print("Registrando pulsaciones de teclado. Presiona Ctrl+C para detener.")
    try:
        while True:
            event = keyboard.read_event()
            if event.event_type == keyboard.KEY_DOWN:
                print(f"Tecla presionada: {event.name}")
    except KeyboardInterrupt:
        print("\nRegistro detenido.")

if __name__ == "__main__":
    log_keypresses()
